output_contract.schema:
{
  "week": "<string: date range>",
  "overall_score": <integer: 0-100>,
  "overall_trend": "<string: improving | stable | declining>",
  "habits": [
    {
      "name": "<string>",
      "target": "<string: e.g., '5 days/week'>",
      "achieved": "<string: e.g., '3 days'>",
      "completion_rate": <integer: percentage 0-100>,
      "status": "<string: exceeded | met | partial | missed>",
      "streak_info": "<string: current streak status or null>"
    }
  ],
  "wins": [
    "<string: specific positive observations, max 3>"
  ],
  "focus_areas": [
    {
      "habit": "<string: habit name>",
      "issue": "<string: what went wrong>",
      "recommendation": "<string: specific action to try next week>"
    }
  ],
  "next_week_priority": "<string: single most important focus>"
}
